const input = $('When Executed by GoPay Change Phone').first().json;
const configured = Number(input.change_phone_max_attempts || input.max_failures || 10);
const maxAttempts = Math.max(1, Number.isFinite(configured) ? configured : 10);
return Array.from({ length: maxAttempts }, (_, index) => ({
  json: { phone_attempt: index + 1, max_attempts: maxAttempts, failure_count: index },
}));

const start = $input.first().json;
const retryAttempts = Math.max(0, Number(start.otp_retry_attempts || 0));
return Array.from({ length: retryAttempts + 1 }, (_, index) => ({
  json: {
    otp_retry_attempt: index,
    activation_id: start.activation_id,
    phone: start.phone,
    state_json: start.state_json || '{}',
    failure_count: start.failure_count || 0,
    otp_timeout_seconds: start.otp_timeout_seconds || 180,
    otp_issued_after_unix: start.otp_issued_after_unix,
  },
}));
